const CIUDADES_CO = ["Bogotá","Medellín","Cali","Barranquilla","Bucaramanga","Pereira","Manizales","Cartagena","Cúcuta","Ibagué","Pasto","Villavicencio","Santa Marta","Montería","Neiva"];

